# ============================================================

def init_db():
    conn = sqlite3.connect(DB_PATH)
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS support_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            timestamp TEXT NOT NULL,
            query TEXT NOT NULL,
            category TEXT,
            urgency TEXT,
            sentiment TEXT,
            complexity TEXT,
            path TEXT,
            confidence TEXT,
            answer_1 TEXT,
            answer_2 TEXT,
            final_answer TEXT,
            sources TEXT
        )
        """
    )
    conn.commit()
    conn.close()


init_db()


def fetch_all_rows() -> pd.DataFrame:
    conn = sqlite3.connect(DB_PATH)
    df = pd.read_sql_query("SELECT * FROM support_log ORDER BY id DESC", conn)
    conn.close()
    return df


# ============================================================
# RAG — TF-IDF RETRIEVAL OVER THE KNOWLEDGE BASE
# ============================================================

@st.cache_resource(show_spinner=False)
def load_knowledge_base(_mtime: float):
    """Chunk the knowledge base file and build a TF-IDF index over it.
    Cached by file modification time, so editing the .txt file automatically
    invalidates the cache without needing to restart the app."""
    if not os.path.exists(KB_PATH):
        return [], None, None

    with open(KB_PATH, "r", encoding="utf-8") as f:
        text = f.read()

    raw_chunks = [c.strip() for c in re.split(r"\n\s*\n", text) if c.strip()]
    # merge tiny fragments (headers, stray lines) into the following chunk
    chunks = []
    buffer = ""
    for c in raw_chunks:
        if len(c) < 40:
            buffer += (c + "\n")
            continue
        chunks.append((buffer + c).strip())
        buffer = ""
    if buffer:
        chunks.append(buffer.strip())

    if not chunks:
        return [], None, None

    vectorizer = TfidfVectorizer(stop_words="english")
    matrix = vectorizer.fit_transform(chunks)
    return chunks, vectorizer, matrix


def retrieve_context(query: str, top_k: int = 3, min_score: float = 0.08):
    kb_mtime = os.path.getmtime(KB_PATH) if os.path.exists(KB_PATH) else 0
    chunks, vectorizer, matrix = load_knowledge_base(kb_mtime)
    if not chunks:
        return []

    q_vec = vectorizer.transform([query])
    sims = cosine_similarity(q_vec, matrix).flatten()
    ranked = sorted(enumerate(sims), key=lambda x: x[1], reverse=True)
    return [(chunks[i], float(score)) for i, score in ranked[:top_k] if score >= min_score]


