def find_cached_match(new_query: str):
    normalized_new = new_query.strip().lower()
    for entry in reversed(st.session_state.history):
        normalized_old = entry["query"].strip().lower()
        if normalized_new == normalized_old:
            return entry
        if _similarity(normalized_new, normalized_old) >= 0.92:
            return entry
    return None


def _similarity(a: str, b: str) -> float:
    import difflib
    return difflib.SequenceMatcher(None, a, b).ratio()


def parse_analysis(text: str):
    category, urgency, sentiment, complexity = "General", "Low", "Neutral", "Complex"
    m = re.search(r"Category:\s*(.+)", text, re.IGNORECASE)
    if m:
        category = m.group(1).strip().splitlines()[0].strip()
    m = re.search(r"Urgency:\s*(.+)", text, re.IGNORECASE)
    if m:
        urgency = m.group(1).strip().splitlines()[0].strip()
    m = re.search(r"Sentiment:\s*(.+)", text, re.IGNORECASE)
    if m:
        sentiment = m.group(1).strip().splitlines()[0].strip()
    m = re.search(r"Complexity:\s*(.+)", text, re.IGNORECASE)
    if m:
        complexity = m.group(1).strip().splitlines()[0].strip()
    return category, urgency, sentiment, complexity


def parse_synthesis(text: str):
    confidence = "Medium"
    final_answer = text.strip()
    followups = []

    m = re.search(r"Confidence:\s*(.+)", text, re.IGNORECASE)
    if m:
        confidence = m.group(1).strip().splitlines()[0].strip()

    m = re.search(r"Final Answer:\s*(.+?)(?:Follow-up Questions:|$)", text, re.IGNORECASE | re.DOTALL)
    if m:
        final_answer = m.group(1).strip()

    fu_match = re.search(r"Follow-up Questions:(.+)", text, re.IGNORECASE | re.DOTALL)
    if fu_match:
        for line in fu_match.group(1).strip().splitlines():
            cleaned = re.sub(r"^\s*[\d\.\-\)]+\s*", "", line).strip()
            if cleaned:
                followups.append(cleaned)

    return confidence, final_answer, followups[:3]


def extract_sources(text: str):
    urls = re.findall(r"https?://[^\s\)\]\,]+", text)
    seen, unique = set(), []
    for u in urls:
        u_clean = u.rstrip(".,)")
        if u_clean not in seen:
            seen.add(u_clean)
            unique.append(u_clean)
    return unique[:5]


