web_search_tool = SerperDevTool()


@tool("Save Customer Support Entry")
def save_customer_entry(
    query: str,
    answer_1: str,
    answer_2: str = "",
    final_answer: str = "",
    category: str = "General",
    urgency: str = "Low",
    sentiment: str = "Neutral",
    complexity: str = "Complex",
    path: str = "full",
    confidence: str = "Medium",
    sources: str = "",
) -> str:
    """
    Save the customer query, both agent answers, the synthesized final answer,
    and the query's classification metadata into the structured SQLite database
    (support_log table) so every interaction is queryable, not just appended as
    flat text.
    """

    conn = sqlite3.connect(DB_PATH)
    conn.execute(
        """
        INSERT INTO support_log
        (timestamp, query, category, urgency, sentiment, complexity, path,
         confidence, answer_1, answer_2, final_answer, sources)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            datetime.now().isoformat(timespec="seconds"),
            query, category, urgency, sentiment, complexity, path,
            confidence, answer_1, answer_2, final_answer, sources,
        ),
    )
    conn.commit()
    conn.close()

    return "The customer support entry was saved successfully to the structured database."


